1898	    DeclareOpInterfaceMethods<OpAsmOpInterface, ["getAsmResultNames", "getAsmBlockArgumentNames"]>
1899	  ]> {
1900	  let summary = "For loop over integer range";
1901	
1902	  let description = [{
1903	    The :code:`for` operation is a structured range-based sequential loop.
1904	
1905	    The loop operation consists of (1) a range formed by :code:`lowerBound`, :code:`upperBound`, and :code:`step`,
1906	    (2) a set of loop-carried values which are initialized by :code:`initValues` and updated by each iteration of the loop, and
1907	    (3) a region which represents the loop body.
1908	
1909	    The iteration space is defined by the interval :math:`[lowerBound, upperBound)` with each value
1910	    separated by :code:`step`.
1911	
1912	    .. math::
1913	
1914	      range(L_b, U_b, S) = \{ L_b + i \cdot S \mid i \in \mathbb{Z}, L_b + i \cdot S < U_b \}
1915	
1916	    :code:`lowerBound`, :code:`upperBound`, and :code:`step` must be of the same type.
1917	    :code:`lowerBound` and :code:`upperBound` specify a half-open (or exclusive) range: the range
1918	    includes the :code:`lowerBound` but does not include the :code:`upperBound`.
1919	    :code:`step` must be positive but the bounds may be negative or zero.
1920	
1921	    The :code:`lowerBound`, :code:`upperBound`, and :code:`step` operands are interpreted as signed integers.
1922	
1923	    The first iteration of the loop receives the induction variable initialized to the value of :code:`lowerBound`
1924	    and the loop-carried values initialized to the values of :code:`initValues`.
1925	
1926	    The loop body is executed for each value in the range, receiving an integer induction variable
1927	    incremented by :code:`step` on each iteration and the loop-carried values which correspond to the
1928	    loop-carried values yielded by the previous loop iteration.
1929	
1930	    The loop terminates when the induction variable is greater than or equal to
1931	    :code:`upperBound`. By default, signed comparison is used between the
1932	    upperBound and the induction variable. To use unsigned comparison instead,
1933	    specify the optional :code:`unsigned` unit attribute.
1934	
1935	    The body of the loop must be terminated by a :ref:`op-cuda_tile.continue` that yields
1936	    the next iteration's value for each loop carried variable.
1937	
1938	    The for operation produces one return value for each loop carried variable. The type of the :math:`i`-th return
1939	    value is that of the :math:`i`-th loop carried variable and its value is the final value of the
1940	    :math:`i`-th loop carried variable.
1941	
1942	    .. warning::
1943	
1944	      - Loop carried variables can not be a :tileirty:`tensor_view` or view type.
1945	      - :code:`for` operations cannot terminate early and must end in a :ref:`op-cuda_tile.continue`.
1946	  }];
1947	
1948	  let mlirExamples = [[{
1949	    # cuda_tile.module @module {
1950	    #   entry @example() {
1951	          %lowerBound = constant <i32: 0> : tile<i32>
1952	          %upperBound = constant <i32: 10> : tile<i32>
1953	          %step = constant <i32: 1> : tile<i32>
1954	
1955	          // A simple loop iterating over an i32 range.
1956	          for %iv in (%lowerBound to %upperBound, step %step) : tile<i32> {
1957	              continue
1958	          }
1959	
1960	          %initVal0 = constant <f32: 0.0> : tile<f32>
1961	          // A similar loop to the above, but with a loop carried value, val0.
1962	          %results = for %iv in (%lowerBound to %upperBound, step %step) : tile<i32>
1963	                              iter_values(%val00 = %initVal0) -> (tile<f32>) {
1964	            %loopVal0 = constant <f32: 1.0> : tile<f32>
1965	            continue %loopVal0 : tile<f32>
1966	          }
1967	    #   }
1968	    # }
1969	  }]];
1970	
1971	  let arguments = (ins
1972	    CudaTileArg<CudaTile_ScalarTileOf<CudaTile_AnyInt>, "The lower bound of the loop.", "13.1">:$lowerBound,
1973	    CudaTileArg<CudaTile_ScalarTileOf<CudaTile_AnyInt>, "The upper bound of the loop.", "13.1">:$upperBound,
1974	    CudaTileArg<CudaTile_ScalarTileOf<CudaTile_AnyInt>, "The step of the loop.", "13.1">:$step,
1975	    CudaTileArg<Variadic<AnyType>, "The initial values of the loop-carried values.", "13.1">:$initValues,
1976	    CudaTileArg<UnitAttr, "If present, use unsigned integer comparison for loop termination.", "13.2">:$unsignedCmp
1977	  );
1978	  let results = (outs CudaTileArg<Variadic<AnyType>, "The values of the loop-carried variables after loop termination.", "13.1">:$resultValues);
1979	  let regions = (region SizedRegion<1>:$region);
1980	
1981	  let skipDefaultBuilders = 1;
1982	  let builders = [
1983	    OpBuilder<(ins "Value":$lowerBound, "Value":$upperBound, "Value":$step,
1984	      CArg<"ValueRange", "{}">:$initArgs,
1985	      CArg<"function_ref<void(OpBuilder &, Location, Value, ValueRange)>",
1986	           "nullptr">,
1987	      CArg<"bool", "false">:$unsignedCmp)>
1988	  ];
1989	
1990	  let extraClassDeclaration = CudaTile_DefaultDialect.classDecl # [{
1991	    Value getInductionVar() { return getBody()->getArgument(0); }
1992	    Block::BlockArgListType getRegionIterValues() {
1993	      return getBody()->getArguments().drop_front(getNumInductionVars());
1994	    }
1995	
1996	    /// Return the `index`-th region iteration argument.
1997	    BlockArgument getRegionIterVar(unsigned index) {
1998	      assert(index < getNumRegionIterVars() &&
